def main():
    json_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), '..', 'src', 'data', 'exam-questions.json')
    with open(json_path, 'r', encoding='utf-8') as f:
        existing = json.load(f)
    print(f"当前题目数: {len(existing)}")
    
    existing_stems = set()
    for q in existing:
        existing_stems.add(q['stem'].strip()[:60])
    
    new_count = 0
    for q in batch7:
        stem = q['stem'].strip()
        if stem[:60] not in existing_stems:
            existing.append(q)
            existing_stems.add(stem[:60])
            new_count += 1
    
    print(f"新增: {new_count}, 总计: {len(existing)}")
    
    with open(json_path, 'w', encoding='utf-8') as f:
        json.dump(existing, f, ensure_ascii=False, indent=2)
    print("已保存!")

if __name__ == '__main__':
    main()
